#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int M, N, C;
        scanf("%d %d %d", &M, &N, &C);
        int L;
        scanf("%d", &L);
        int plots[L][5];
        for (int i = 0; i < L; i++) {
            scanf("%d %d %d %d %d", &plots[i][0], &plots[i][1], &plots[i][2], &plots[i][3], &plots[i][4]);
        }
        long long maxArea = 0;
        for (int x = 0; x < M; x++) {
            for (int y = 0; y < N; y++) {
                for (int w = 1; w <= M - x; w++) {
                    for (int h = 1; h <= N - y; h++) {
                        long long cost = 0;
                        for (int i = 0; i < L; i++) {
                            if (x <= plots[i][0] + plots[i][2] && x + w >= plots[i][0] && y <= plots[i][1] + plots[i][3] && y + h >= plots[i][1]) {
                                cost += plots[i][4];
                            }
                        }
                        if (cost <= C) {
                            maxArea = (maxArea > (long long)w * h) ? maxArea : (long long)w * h;
                        }
                    }
                }
            }
        }
        printf("Case %d: %lld\n", T - T + 1, maxArea);
    }
    return 0;
}

