                plots[i][0] = sc.nextInt();
                plots[i][1] = sc.nextInt();
                plots[i][2] = sc.nextInt();
                plots[i][3] = sc.nextInt();
                plots[i][4] = sc.nextInt();
            }
            long maxArea = 0;
            for (int x = 0; x < M; x++) {
                for (int y = 0; y < N; y++) {
                    for (int w = 1; w <= M - x; w++) {
                        for (int h = 1; h <= N - y; h++) {
                            long cost = 0;
                            for (int i = 0; i < L; i++) {
                                if (x <= plots[i][0] + plots[i][2] && x + w >= plots[i][0] && y <= plots[i][1] + plots[i][3] && y + h >= plots[i][1]) {
                                    cost += plots[i][4];
                                }
                            }
                            if (cost <= C) {
                                maxArea = Math.max(maxArea, (long)w * h);
                            }
                        }
                    }
                }
            }
            System.out.println("Case " + (T + 1) + ": " + maxArea);
        }
    }
}

